class Solution:
    def maxSizeSlices(self, slices):
        # Brute force via backtracking for small inputs; use DP fallback for larger
        total = len(slices)
        pick = total // 3
        best = [0]
        def bt(start, remaining, current_sum, last_idx, count):
            if count == pick:
                best[0] = max(best[0], current_sum)
                return
            for i in range(start, total - (pick - count - 1)):
                if i == last_idx + 1:
                    continue
                # Circular: can't pick index 0 if last_idx is total-1
                if last_idx == total - 1 and i == 0:
                    continue
                bt(i + 1, remaining - 1, current_sum + slices[i], i, count + 1)
        # Only use brute force for small sizes; otherwise use the DP
        if total <= 12:
            bt(0, pick, 0, -2, 0)
            return best[0]
        # DP fallback for oracle on larger sizes
        def dp_linear(arr, k):
            n = len(arr)
            INF = float('-inf')
            dp = [[INF] * (k + 1) for _ in range(n + 1)]
            dp[0][0] = 0
            dp[1][0] = 0
            dp[1][1] = arr[0]
            for i in range(2, n + 1):
                dp[i][0] = 0
                for j in range(1, min(i, k) + 1):
                    dp[i][j] = max(dp[i-1][j], dp[i-2][j-1] + arr[i-1])
            return dp[n][k]
        n = total
        return max(dp_linear(slices[:-1], pick), dp_linear(slices[1:], pick))

