class Solution:
    def maxSizeSlices(self, slices):
        def dp(arr, k):
            n = len(arr)
            INF = float('-inf')
            prev2 = [INF] * (k + 1)
            prev1 = [INF] * (k + 1)
            prev2[0] = 0
            prev1[0] = 0
            prev1[1] = arr[0]
            for i in range(2, n + 1):
                curr = [INF] * (k + 1)
                curr[0] = 0
                for j in range(1, min(i, k) + 1):
                    curr[j] = max(prev1[j], prev2[j-1] + arr[i-1] if j >= 1 else INF)
                prev2, prev1 = prev1, curr
            return prev1[k]
        n = len(slices)
        return max(dp(slices[:-1], n // 3), dp(slices[1:], n // 3))

