var maxSizeSlices = function(slices) {
    function dp(arr, k) {
        const n = arr.length;
        const INF = -Infinity;
        let prev2 = new Array(k + 1).fill(INF);
        let prev1 = new Array(k + 1).fill(INF);
        prev2[0] = 0;
        prev1[0] = 0;
        if (k >= 1) prev1[1] = arr[0];
        for (let i = 2; i <= n; i++) {
            const curr = new Array(k + 1).fill(INF);
            curr[0] = 0;
            for (let j = 1; j <= Math.min(i, k); j++) {
                curr[j] = Math.max(prev1[j], j >= 1 && prev2[j-1] !== INF ? prev2[j-1] + arr[i-1] : INF);
            }
            prev2 = prev1;
            prev1 = curr;
        }
        return prev1[k];
    }
    const n = slices.length;
    const k = Math.floor(n / 3);
    return Math.max(dp(slices.slice(0, n - 1), k), dp(slices.slice(1), k));
};
